  "test_code": "import pytest


class FakeService:
    """A simple fake external service to mimic production behavior in fast regression."""

    def __init__(self, should_fail=False, latency_ms=0):
        self.should_fail = should_fail
        self.latency_ms = latency_ms

    def do_work(self, payload: dict) -> dict:
        if self.should_fail:
            raise RuntimeError("Service failure")
        # fast lane: no real sleep, just assert latency budget via configuration
        return {
            "status": "ok",
            "echo": payload,
            "latency_ms": self.latency_ms,
        }


def process_request(payload: dict, service: FakeService) -> dict:
    """Core logic under fast-lane regression.

    This is a sample function representing the main path of the system:
    - validates input structure
    - calls an external service (here: FakeService)
    - normalizes the response
    """
    if not isinstance(payload, dict):
        raise TypeError("payload must be dict")

    if "id" not in payload or "value" not in payload:
        raise ValueError("missing required keys: id, value")

    if not isinstance(payload["id"], int):
        raise TypeError("id must be int")

    response = service.do_work(payload)

    return {
        "id": payload["id"],
        "result": response["echo"]["value"],
        "service_status": response["status"],
    }


# -------------------------
# Fast lane regression tests
# -------------------------

@pytest.fixture
def fast_lane_service():
    """A fast, deterministic fake service for regression checks."""
    return FakeService(should_fail=False, latency_ms=5)


def test_fast_lane_happy_path(fast_lane_service):
    """Main success path: ensures the core behavior is intact."""
    payload = {"id": 1, "value": "foo"}

    result = process_request(payload, fast_lane_service)

    assert result["id"] == 1
    assert result["result"] == "foo"
    assert result["service_status"] == "ok"


@pytest.mark.parametrize(
    "payload,expected_error",
    [
        (None, TypeError),
        ({}, ValueError),
        ({"id": "1", "value": "x"}, TypeError),
        ({"id": 1}, ValueError),
    ],
)
def test_fast_lane_input_validation(payload, expected_error, fast_lane_service):
    """Fast regression on input validation: type and required fields."""
    with pytest.raises(expected_error):
        process_request(payload, fast_lane_service)


def test_fast_lane_service_error_is_propagated():
    """Service errors must not silently succeed in the fast lane path."""
    failing_service = FakeService(should_fail=True)
    payload = {"id": 2, "value": "bar"}

    with pytest.raises(RuntimeError):
        process_request(payload, failing_service)


def test_fast_lane_regression_is_deterministic(fast_lane_service):
    """Fast lane should be deterministic across invocations (no randomness, timing-free)."""
    payload = {"id": 3, "value": "baz"}

    result1 = process_request(payload, fast_lane_service)
    result2 = process_request(payload, fast_lane_service)

    assert result1 == result2


@pytest.mark.parametrize("value", ["quick", "smoke", "regression"])
def test_fast_lane_minimal_data_variations(fast_lane_service, value):
    """Small set of representative inputs to detect obvious regressions quickly."""
    payload = {"id": 10, "value": value}

    result = process_request(payload, fast_lane_service)

    assert result["id"] == 10
    assert result["result"] == value


def test_fast_lane_does_not_depend_on_real_network(monkeypatch):
    """Guarantee that fast regression does not call real external resources."""

    class NetworkService:
        def call_remote(self):  # pragma: no cover - safety check only
            raise AssertionError("Real network should not be used in fast lane")

    # Illustrative target that would be patched in real code
    dummy_target = NetworkService()

    def fake_remote():
        return "stubbed"

    monkeypatch.setattr(dummy_target, "call_remote", fake_remote)

    assert dummy_target.call_remote() == "stubbed"
",
  "testimony": "These tests implement a fast lane regression check by focusing on the shortest, most stable path through the core logic, using only in-memory fakes and avoiding real I/O:

1. test_fast_lane_happy_path: Verifies that the main success scenario (valid payload, healthy service) produces the expected normalized output. This guards against accidental changes in the primary functional path.
2. test_fast_lane_input_validation: Checks key validation rules (type checks and required keys) using a small parameterized matrix. This quickly detects regressions in input contracts without broad combinatorial explosion.
3. test_fast_lane_service_error_is_propagated: Ensures that when the service fails, the error is surfaced instead of being silently swallowed or mis-translated. This is critical for detecting behavior-breaking changes in error handling.
4. test_fast_lane_regression_is_deterministic: Confirms that repeated invocations with the same input and fake service produce identical results, catching hidden sources of nondeterminism that could destabilize a fast regression suite.
5. test_fast_lane_minimal_data_variations: Runs a tiny, representative set of input values through the main path to broaden coverage just enough to detect obvious regressions in value handling while keeping execution fast.
6. test_fast_lane_does_not_depend_on_real_network: Demonstrates and enforces the rule that fast-lane regression must not touch real external services by requiring stubbed behavior via monkeypatch. This keeps the suite reliable, fast, and independent of the environment.

Collectively, these tests form a light but effective safety net that can be executed frequently (e.g., on each commit) to catch core regressions early while maintaining very low runtime and zero external dependencies, which is the essence of a “fast lane regression check.”"
}

